/**
 * compile-data.ts — Static data pipeline for Myrdl
 * Generates src/data/valid-words.json, src/data/answers.json, src/data/etymology.json
 * Run: npx tsx scripts/compile-data.ts
 */

import { readFileSync, writeFileSync, mkdirSync } from 'fs'
import { resolve, dirname } from 'path'
import { fileURLToPath } from 'url'

const __dirname = dirname(fileURLToPath(import.meta.url))
const projectRoot = resolve(__dirname, '..')
const dataDir = resolve(projectRoot, 'src', 'data')

// ─── Extract word arrays from wordle-wordlist cache (bypasses module bug) ───

const wordleIndexPath = resolve(projectRoot, 'node_modules', 'wordle-wordlist', 'index.js')
const wordleSource = readFileSync(wordleIndexPath, 'utf8')

const guessesMatch = wordleSource.match(/guessesOnly:\s*(\[.*?\]),\s*\n/s)
const answersMatch = wordleSource.match(/answers:\s*(\[.*?\]),\s*\n/s)

if (!guessesMatch || !answersMatch) {
  console.error('[compile-data] ERROR: Could not parse wordle-wordlist cache')
  process.exit(1)
}

const guessesOnly: string[] = JSON.parse(guessesMatch[1])
const answerWords: string[] = JSON.parse(answersMatch[1])

// ─── valid-words.json: all valid guesses = guessesOnly + answers ─────────────

const allValid = [...new Set([...guessesOnly, ...answerWords].map(w => w.toLowerCase()))]
  .filter(w => w.length === 5 && /^[a-z]+$/.test(w))
  .sort()

console.log(`[compile-data] valid-words: ${allValid.length} entries`)

if (allValid.length < 10000) {
  console.error(`[compile-data] ERROR: valid-words has only ${allValid.length} entries (need >= 10000)`)
  process.exit(1)
}

// ─── answers.json: seeded-shuffle sequence ───────────────────────────────────
//
// Myrdl uses its own deterministic answer sequence — not alphabetical, not
// the original NYT Wordle order. A Fisher-Yates shuffle seeded with a fixed
// Myrdl-specific value produces a stable, non-predictable ordering that is
// consistent forever (same seed always yields the same sequence).
//
// IMPORTANT: Never change MYRDL_ANSWER_SEED after launch. Changing it would
// re-order the entire answer list and invalidate all existing player streaks.

const MYRDL_ANSWER_SEED = 0x4d797264 // 'Myrd' in ASCII hex

function mulberry32(seed: number): () => number {
  let s = seed
  return () => {
    s = (s + 0x6d2b79f5) | 0
    let t = Math.imul(s ^ (s >>> 15), 1 | s)
    t = (t + Math.imul(t ^ (t >>> 7), 61 | t)) ^ t
    return ((t ^ (t >>> 14)) >>> 0) / 4294967296
  }
}

function seededShuffle(arr: string[], seed: number): string[] {
  const result = [...arr]
  const rand = mulberry32(seed)
  for (let i = result.length - 1; i > 0; i--) {
    const j = Math.floor(rand() * (i + 1))
    ;[result[i], result[j]] = [result[j], result[i]]
  }
  return result
}

const validSet = new Set(allValid)
const answers = seededShuffle(
  [...new Set(answerWords.map(w => w.toLowerCase()).filter(w => validSet.has(w)))],
  MYRDL_ANSWER_SEED,
)

console.log(`[compile-data] answers: ${answers.length} entries`)

if (answers.length < 2000) {
  console.error(`[compile-data] ERROR: answers has only ${answers.length} entries (need >= 2000)`)
  process.exit(1)
}

