// Generate stub for any answer not in curated set
const etymologyData: Record<string, EtymologyEntry> = {}

for (const word of answers) {
  const upperWord = word.toUpperCase()
  if (curatedEtymology[upperWord]) {
    etymologyData[upperWord] = curatedEtymology[upperWord]
  } else {
    // Generate a basic stub — real etymology to be sourced for production
    etymologyData[upperWord] = {
      pos: 'noun',
      definition: `A five-letter English word.`,
      origin: 'English',
    }
  }
}

const etymologyCoverage = answers.filter(w => curatedEtymology[w.toUpperCase()]).length
console.log(
  `[compile-data] etymology: ${Object.keys(etymologyData).length} entries ` +
    `(${etymologyCoverage} curated, ${answers.length - etymologyCoverage} stubs)`,
)

// ─── Write JSON files ─────────────────────────────────────────────────────────

mkdirSync(dataDir, { recursive: true })

writeFileSync(resolve(dataDir, 'valid-words.json'), JSON.stringify(allValid, null, 2))
console.log(`[compile-data] ✅ Wrote src/data/valid-words.json (${allValid.length} words)`)

writeFileSync(resolve(dataDir, 'answers.json'), JSON.stringify(answers, null, 2))
console.log(`[compile-data] ✅ Wrote src/data/answers.json (${answers.length} words)`)

writeFileSync(resolve(dataDir, 'etymology.json'), JSON.stringify(etymologyData, null, 2))
console.log(`[compile-data] ✅ Wrote src/data/etymology.json (${Object.keys(etymologyData).length} entries)`)

console.log('[compile-data] ✅ Data pipeline complete.')
